#include "controller.h"

static void controller_set_safe_idle(controller_t *controller)
{
    controller->inlet_open = false;
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_IDLE;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_idle(controller);
    controller->has_valid_temperature = false;
    controller->previous_temperature_c = 0;
    controller->last_temperature_c = 0;
    controller->last_temperature_ms = 0U;
    controller->has_valid_level = false;
    controller->last_level = 0;
    controller->last_level_ms = 0U;
}

static bool controller_check_sensor_timeout(controller_t *controller, uint32_t now_ms)
{
    if (controller->has_valid_temperature && (now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        return true;
    }
    if (controller->has_valid_level && (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
        return true;
    }
    return false;
}

static void controller_update_sensor_freshness(controller_t *controller, uint32_t now_ms)
{
    if (controller->has_valid_temperature && !controller->has_valid_level) {
        // Temperature is fresh but level is stale - check for timeout
        if ((now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS) ||
            (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
            controller_set_safe_idle(controller);
        }
    } else if (!controller->has_valid_temperature && controller->has_valid_level) {
        // Level is fresh but temperature is stale - check for timeout
        if ((now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS) ||
            (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
            controller_set_safe_idle(controller);
        }
    } else if (controller->has_valid_temperature && controller->has_valid_level) {
        // Both are valid, check for timeout
        if ((now_ms - controller->last_temperature_ms > CONTROLLER_SENSOR_TIMEOUT_MS) ||
            (now_ms - controller->last_level_ms > CONTROLLER_SENSOR_TIMEOUT_MS)) {
            controller_set_safe_idle(controller);
        }
    }
}

static void controller_determine_output(controller_t *controller, uint32_t now_ms)
{
    // Check for sensor timeout first - forces safe idle
    if (controller_check_sensor_timeout(controller, now_ms)) {
        controller_set_safe_idle(controller);
        return;
    }

    // Stay in safe all-off state until both sensors have been seen validly
    if (!controller->has_valid_temperature || !controller->has_valid_level) {
        controller_set_safe_idle(controller);
        return;
    }

    int level = controller->last_level;
    int temp = controller->last_temperature_c;
    bool was_heating = (controller->state == CONTROLLER_STATE_HEATING);

    // Control policy implementation
    if (level < 55) {
        // If LEVEL < 55 at any time, keep HEATER OFF
        controller->inlet_open = (level < 60);
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
    } else if (level > 75) {
        // If LEVEL > 75, command INLET CLOSED
        controller->inlet_open = false;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_SAFE_IDLE;
    } else if (level >= 60 && level <= 75) {
        // Safe level region - apply temperature-based logic
        if (temp < 45) {
            // If 60 <= LEVEL <= 75 and TEMP < 45, command INLET CLOSED and HEATER ON
            controller->inlet_open = false;
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        } else if (temp >= 45 && temp < 47) {
            // If 45 <= TEMP < 47, command INLET CLOSED and hold previous safe heater state
            controller->inlet_open = false;
            controller->heater_on = was_heating;
            controller->state = CONTROLLER_STATE_HOLDING;
        } else if (temp >= 47 && temp <= 48) {
            // If 47 <= TEMP <= 48, check temperature trend
            if (controller->previous_temperature_c < controller->last_temperature_c) {
                // Temperature is rising - command HEATER OFF early
                controller->inlet_open = false;
                controller->heater_on = false;
                controller->state = CONTROLLER_STATE_HOLDING;
            } else {
                // Temperature not rising - hold previous safe heater state
                controller->inlet_open = false;
                controller->heater_on = was_heating;
                controller->state = CONTROLLER_STATE_HOLDING;
            }
        } else if (temp > 48) {
            // If TEMP > 48, command INLET CLOSED and HEATER OFF
            controller->inlet_open = false;
            controller->heater_on = false;
            controller->state = CONTROLLER_STATE_SAFE_IDLE;
        } else {
            // temp < 45 (already handled above), but catch any other case
            controller->inlet_open = false;
            controller->heater_on = true;
            controller->state = CONTROLLER_STATE_HEATING;
        }
    } else {
        // level < 60 and >= 55 - transition to filling
        controller->inlet_open = true;
        controller->heater_on = false;
        controller->state = CONTROLLER_STATE_FILLING;
    }
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .inlet_open = false,
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_IDLE,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_IDLE),
        .changed = false,
        .timed_out = false,
    };
    bool previous_inlet_open;
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    previous_inlet_open = controller->inlet_open;
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    // Handle sensor timeout - forces safe idle
    if (input.kind == CONTROLLER_INPUT_SENSOR_TIMEOUT) {
        controller_set_safe_idle(controller);
        output.timed_out = true;
    } else if (input.kind == CONTROLLER_INPUT_INVALID_TEMPERATURE || input.kind == CONTROLLER_INPUT_INVALID_LEVEL) {
        // Malformed input - reset validity and go to safe idle
        controller->has_valid_temperature = false;
        controller->has_valid_level = false;
        controller_set_safe_idle(controller);
        output.timed_out = true;
    } else if (input.kind == CONTROLLER_INPUT_NONE) {
        // No new input - check for sensor timeout
        if (controller_check_sensor_timeout(controller, input.now_ms)) {
            controller_set_safe_idle(controller);
            output.timed_out = true;
        }
        return output;
    }

    // Update sensor freshness and determine output
    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_temperature = true;
        controller->previous_temperature_c = controller->last_temperature_c;
        controller->last_temperature_c = input.temperature_c;
        controller->last_temperature_ms = input.now_ms;
        break;
    case CONTROLLER_INPUT_LEVEL:
        controller->has_valid_level = true;
        controller->last_level = input.level;
        controller->last_level_ms = input.now_ms;
        break;
    default:
        break;
    }

    // Determine output based on control policy
    controller_determine_output(controller, input.now_ms);

    output.inlet_open = controller->inlet_open;
    output.heater_on = controller->heater_on;
    output.state = controller->state;
    output.state_name = controller_state_name(controller->state);
    output.changed =
        (previous_inlet_open != controller->inlet_open) ||
        (previous_heater_on != controller->heater_on) ||
        (previous_state != controller->state);
    return output;
}

const char *controller_state_name(controller_state_t state)
{
    switch (state) {
    case CONTROLLER_STATE_FILLING:
        return "STATE FILLING";
    case CONTROLLER_STATE_HEATING:
        return "STATE HEATING";
    case CONTROLLER_STATE_HOLDING:
        return "STATE HOLDING";
    case CONTROLLER_STATE_SAFE_IDLE:
    default:
        return "STATE SAFE_IDLE";
    }
}

