def test_boot_leaves_inlet_closed_and_heater_off(self) -> None:
        """Boot leaves the inlet closed and the heater off."""
        artifact_dir = self_test_artifact_dir("controller_boot")
        with FirmwareSession(artifact_dir=artifact_dir) as session:
            # Read all lines until we see both boot completion AND at least one ACT line
            has_boot = False
            has_act = False
            act_lines = []

            while True:
                try:
                    lines = session.read_lines(timeout_s=0.5)
                    if not lines:
                        break

                    for line in lines:
                        if "DBG BOOTED" in line or "main_task: Returned from app_main()" in line:
                            has_boot = True
                        if "ACT" in line and not has_act:
                            has_act = True
                            act_lines.append(line)

                    # If we have both boot and at least one ACT line, we're done
                    if has_boot and has_act:
                        break

                except TimeoutError:
                    break

            self.assertTrue(has_boot, "Boot message not seen")
            self.assertTrue(has_act, f"No ACT lines found after boot. All lines: {session.read_lines(timeout_s=0.5)}")

            # Find the first ACT line (excluding duplicate reads)
            self.assertTrue(act_lines, "No ACT lines collected")
            self.assertIn("CLOSED", act_lines[0])  # ACT INLET CLOSED
            if len(act_lines) > 1:
                self.assertIn("OFF", act_lines[1])  # ACT HEATER OFF

